import json
import pandas as pd
import re

# Load the Swift files data
swift_files = locals()['var_functions.execute_python:12']
df = pd.DataFrame(swift_files)

# Extract copy count from repo_data_description
def extract_copy_count(description):
    # Look for patterns like "duplicated X times", "appears X times", "copied X times", "repeated X times"
    patterns = [r'duplicated (\d+) times', r'appears (\d+) times', r'copied (\d+) times', r'repeated (\d+) times']
    for pattern in patterns:
        match = re.search(pattern, description, re.IGNORECASE)
        if match:
            return int(match.group(1))
    return 0

# Extract copy count and check if it's non-binary
def is_non_binary(description):
    return 'non-binary' in description.lower() or 'non-binary content file' in description.lower()

df['copy_count'] = df['repo_data_description'].apply(extract_copy_count)
df['is_non_binary'] = df['repo_data_description'].apply(is_non_binary)

# Filter for non-binary files and find the one with max copy count
non_binary_swift = df[df['is_non_binary'] == True]
if not non_binary_swift.empty:
    max_copies = non_binary_swift['copy_count'].max()
    most_copied_files = non_binary_swift[non_binary_swift['copy_count'] == max_copies]

    result = {
        'max_copy_count': int(max_copies),
        'files': most_copied_files.to_dict('records')
    }
else:
    result = {'error': 'No non-binary Swift files found'}

print("__RESULT__:")
print(json.dumps(result))

